import asyncio
from typing import List
from collectors.base import BaseCollector
from utils import HotItem, logger


class DouyinCollector(BaseCollector):
    platform_name = "douyin"

    async def collect(self, max_items: int = 10) -> List[HotItem]:
        items = []
        try:
            from playwright.async_api import async_playwright

            async with async_playwright() as p:
                browser = await p.chromium.launch(
                    headless=True,
                    args=["--no-sandbox", "--disable-blink-features=AutomationControlled"],
                )
                context = await browser.new_context(
                    user_agent=(
                        "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
                        "AppleWebKit/537.36 (KHTML, like Gecko) "
                        "Chrome/120.0.0.0 Safari/537.36"
                    ),
                    viewport={"width": 1920, "height": 1080},
                )
                page = await context.new_page()

                try:
                    await page.goto(
                        "https://www.douyin.com/hot",
                        wait_until="domcontentloaded",
                        timeout=30000,
                    )
                    # 等待热点列表加载
                    await asyncio.sleep(3)

                    # 尝试多种选择器抓取热点标题
                    hot_items = await page.eval_on_selector_all(
                        "[class*='hot'] a, [class*='title'] a, [class*='card'] a, .hot-list a",
                        "els => els.map(el => ({ title: el.textContent?.trim(), href: el.href }))",
                    )

                    if not hot_items or all(not x.get("title") for x in hot_items):
                        # 兜底：尝试常见的抖音热点结构
                        hot_items = await page.evaluate("""
                            () => {
                                const items = [];
                                document.querySelectorAll('a').forEach(a => {
                                    const text = a.textContent?.trim();
                                    if (text && text.length > 4 && text.length < 50) {
                                        items.push({ title: text, href: a.href });
                                    }
                                });
                                return items.slice(0, 20);
                            }
                        """)

                    seen = set()
                    for item in hot_items:
                        title = (item.get("title") or "").strip()
                        if title and title not in seen and len(title) > 4:
                            seen.add(title)
                            items.append(HotItem(
                                platform="抖音",
                                title=title,
                                url=item.get("href", ""),
                                hot_score="热点榜",
                                description="",
                                author="",
                            ))
                            if len(items) >= max_items:
                                break
                finally:
                    await browser.close()
        except Exception as e:
            logger.error(f"抖音抓取失败: {e}")
        return items

