                            if len(items) >= max_items:
                                break

                    if not items:
                        logger.info("小红书未抓到内容（可能需要登录）")
                finally:
                    await browser.close()
        except Exception as e:
            logger.error(f"小红书抓取失败: {e}")
        return items

