import httpx
from utils import logger, today_str


def push_to_wechat(webhook_url: str, title: str, content: str) -> bool:
    """通过企业微信群机器人发送Markdown消息"""
    if not webhook_url:
        logger.error("企业微信Webhook URL未配置")
        return False

    # 企业微信Markdown消息体（正文最多4096字节）
    md_content = f"# {title}\n\n{content}"

    # 加上签名
    md_content += f"\n\n---\n*每日热点日报 · {today_str()} · 由AI自动生成*"

    payload = {
        "msgtype": "markdown",
        "markdown": {
            "content": md_content[:4096],
        },
    }

    try:
        resp = httpx.post(webhook_url, json=payload, timeout=10)
        result = resp.json()
        if result.get("errcode") == 0:
            logger.info("企业微信推送成功")
            return True
        else:
            logger.error(f"企业微信推送失败: {result}")
            return False
    except Exception as e:
        logger.error(f"企业微信推送异常: {e}")
        return False


def push_text_to_wechat(webhook_url: str, content: str) -> bool:
    """通过企业微信群机器人发送纯文本消息（备用）"""
    if not webhook_url:
        return False

    payload = {
        "msgtype": "text",
        "text": {
            "content": content[:2048],
        },
    }

    try:
        resp = httpx.post(webhook_url, json=payload, timeout=10)
        result = resp.json()
        return result.get("errcode") == 0
    except Exception as e:
        logger.error(f"企业微信文本推送异常: {e}")
        return False

