import asyncio
from typing import List
from collectors.base import BaseCollector
from utils import HotItem, logger


class ZhihuCollector(BaseCollector):
    platform_name = "zhihu"

    async def collect(self, max_items: int = 10) -> List[HotItem]:
        items = []
        try:
            from playwright.async_api import async_playwright

            async with async_playwright() as p:
                browser = await p.chromium.launch(
                    headless=True,
                    args=["--no-sandbox"],
                )
                context = await browser.new_context(
                    user_agent=(
                        "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
                        "AppleWebKit/537.36 (KHTML, like Gecko) "
                        "Chrome/120.0.0.0 Safari/537.36"
                    ),
                    viewport={"width": 1920, "height": 1080},
                )
                page = await context.new_page()

                try:
                    await page.goto(
                        "https://www.zhihu.com/hot",
                        wait_until="domcontentloaded",
                        timeout=30000,
                    )
                    await asyncio.sleep(3)

                    raw_items = await page.evaluate("""
                        (max) => {
                            const results = [];
                            const cards = document.querySelectorAll('.HotList-item, [class*="HotItem"], .hot-card');
                            cards.forEach(card => {
                                const link = card.querySelector('a');
                                const titleEl = card.querySelector('[class*="title"], h2');
                                const hotEl = card.querySelector('[class*="hot"], [class*="score"], [class*="metrics"]');
                                if (titleEl) {
                                    const title = titleEl.textContent?.trim();
                                    if (title && title.length > 3) {
                                        results.push({
                                            title: title,
                                            href: link ? link.href : '',
                                            hot: hotEl ? hotEl.textContent?.trim() : '',
                                        });
                                    }
                                }
                            });
                            return results.slice(0, max);
                        }
                    """, max_items)

                    items = [
                        HotItem(
                            platform="知乎",
                            title=item.get("title", ""),
                            url=item.get("href", ""),
                            hot_score=f"热度: {item.get('hot', '')}" if item.get("hot") else "",
                            description="",
                            author="",
                        )
                        for item in raw_items if item.get("title")
                    ]
                finally:
                    await browser.close()
        except Exception as e:
            logger.error(f"知乎抓取失败: {e}")
        return items

