import asyncio
from typing import List
from collectors.base import BaseCollector
from utils import HotItem, logger


class ZhihuCollector(BaseCollector):
    platform_name = "zhihu"

    async def collect(self, max_items: int = 10) -> List[HotItem]:
        items = []
        try:
            from playwright.async_api import async_playwright

            async with async_playwright() as p:
                browser = await p.chromium.launch(
                    headless=True,
                    args=["--no-sandbox"],
                )
                context = await browser.new_context(
                    user_agent=(
                        "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
                        "AppleWebKit/537.36 (KHTML, like Gecko) "
                        "Chrome/120.0.0.0 Safari/537.36"
                    ),
                    viewport={"width": 1920, "height": 1080},
                    locale="zh-CN",
                )
                page = await context.new_page()

                try:
                    # 先尝试直接请求知乎热榜API（带cookie）
                    api_data = await self._try_api()
                    if api_data:
                        return api_data[:max_items]

                    # API失败，尝试用浏览器访问热榜页
                    await page.goto(
                        "https://www.zhihu.com/hot",
                        wait_until="networkidle",
                        timeout=30000,
                    )
                    await asyncio.sleep(3)

                    # 检查是否被拦截（登录页）
                    page_text = await page.evaluate("() => document.body.innerText")
                    if not page_text or "登录" in page_text[:200]:
                        logger.info("知乎页面需登录，尝试其他入口")
                        # 尝试探索页
                        await page.goto(
                            "https://www.zhihu.com/explore",
                            wait_until="networkidle",
                            timeout=30000,
                        )
                        await asyncio.sleep(3)

                    # 通用抓取：获取页面中所有带链接的标题
                    raw_items = await page.evaluate("""
                        (max) => {
                            const results = [];
                            const seen = new Set();
                            // 尝试各种选择器
                            const selectors = [
                                'a[href*="/question/"]',
                                'a[href*="/answer/"]',
                                'a[href*="/pin/"]',
                                '[class*="title"] a',
                                '[class*="Title"] a',
                                'h2 a',
                                'h1 a',
                            ];
                            for (const sel of selectors) {
                                document.querySelectorAll(sel).forEach(el => {
                                    const title = el.textContent?.trim();
                                    const href = el.href || '';
                                    if (title && title.length > 5 && !seen.has(title)) {
                                        seen.add(title);
                                        results.push({ title, href });
                                    }
                                });
                            }
                            return results.slice(0, max);
                        }
                    """, max_items)

                    items = [
                        HotItem(
                            platform="知乎",
                            title=item.get("title", ""),
                            url=item.get("href", ""),
                            hot_score="",
                            description="",
                            author="",
                        )
                        for item in raw_items if item.get("title")
                    ]
                finally:
                    await browser.close()
        except Exception as e:
            logger.error(f"知乎抓取失败: {e}")
        return items

    async def _try_api(self) -> List[HotItem]:
        """尝试直接调用知乎API"""
        try:
            import httpx
            headers = {
                "User-Agent": (
                    "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
                    "AppleWebKit/537.36 (KHTML, like Gecko) "
                    "Chrome/120.0.0.0 Safari/537.36"
                ),
                "Referer": "https://www.zhihu.com/",
                "x-requested-with": "XMLHttpRequest",
            }
            # 尝试使用 zhuanlan 的 API
            async with httpx.AsyncClient(timeout=10) as client:
                resp = await client.get(
                    "https://www.zhihu.com/api/v3/feed/topstory/hot-lists/total",
                    headers=headers,
                    params={"limit": 10, "desktop": "true"},
                )
                if resp.status_code == 200:
                    data = resp.json()
                    result = []
                    for entry in data.get("data", []):
                        target = entry.get("target", {})
                        title = target.get("title", "")
                        id_str = target.get("id", "")
                        url = f"https://www.zhihu.com/question/{id_str}" if id_str else ""
                        detail = entry.get("detail_text", "")
                        result.append(HotItem(
                            platform="知乎",
                            title=title,
                            url=url,
                            hot_score=f"热度: {detail}" if detail else "",
                            description="",
                            author="",
                        ))
                    return result
        except Exception:
            pass
        return []

