import re
import httpx
from utils import logger, today_str


def _truncate_bytes(text: str, max_bytes: int = 4096) -> str:
    """按字节截断字符串，保留完整字符"""
    encoded = text.encode("utf-8")
    if len(encoded) <= max_bytes:
        return text
    truncated = encoded[:max_bytes]
    while truncated and truncated[-1] & 0xC0 == 0x80:
        truncated = truncated[:-1]
    if truncated and truncated[-1] & 0x80:
        truncated = truncated[:-1]
    return truncated.decode("utf-8", errors="ignore")


def _send_single(webhook_url: str, content: str) -> bool:
    """发送单条Markdown消息"""
    if not content.strip():
        return True
    content = _truncate_bytes(content, 4096)
    try:
        resp = httpx.post(webhook_url, json={
            "msgtype": "markdown",
            "markdown": {"content": content},
        }, timeout=10)
        result = resp.json()
        if result.get("errcode") == 0:
            return True
        logger.error(f"推送失败: {result}")
        return False
    except Exception as e:
        logger.error(f"推送异常: {e}")
        return False


def push_to_wechat(webhook_url: str, title: str, content: str) -> bool:
    """按 ## 分段发送多条Markdown消息，绕过4096字节限制"""
    if not webhook_url:
        logger.error("企业微信Webhook URL未配置")
        return False

    date_str = today_str()
    signature = f"\n\n---\n*每日热点日报 · {date_str} · 由AI自动生成*"

    # 按 ## 标题分割内容
    sections = re.split(r'(?=^## )', content, flags=re.MULTILINE)
    sections = [s.strip() for s in sections if s.strip()]

    if not sections:
        return _send_single(webhook_url, f"# {title}\n\n{content}{signature}")

    all_ok = True

    # 第一条：大标题 + 第一个段落（热点速览）
    first = f"# {title}\n\n{sections[0]}"
    all_ok &= _send_single(webhook_url, first)

    # 中间段落：爆款拆解（每个拆解可能再按 ### 细分）
    current_chunk = ""
    for section in sections[1:]:
        # 检测是否是 "要点总结" 段落，放到最后
        if "要点总结" in section or "总结" in section[:20]:
            continue

        msg = f"## {section}"
        # 如果单段太长，拆成多个
        msg_bytes = msg.encode("utf-8")
        if len(msg_bytes) > 4096 and "### " in section:
            # 按 ### 进一步拆分
            subs = re.split(r'(?=^### )', section, flags=re.MULTILINE)
            sub_chunk = ""
            for sub in subs:
                sub = sub.strip()
                if not sub:
                    continue
                candidate = f"## {sub_chunk}\n\n{sub}" if sub_chunk else f"## {sub}"
                if len(candidate.encode("utf-8")) > 4000:
                    if sub_chunk:
                        all_ok &= _send_single(webhook_url, f"## {sub_chunk}")
                    all_ok &= _send_single(webhook_url, f"## {sub}")
                    sub_chunk = ""
                else:
                    sub_chunk = (sub_chunk + "\n\n" + sub) if sub_chunk else sub
            if sub_chunk:
                all_ok &= _send_single(webhook_url, f"## {sub_chunk}")
        else:
            current_chunk = current_chunk + "\n\n" + section if current_chunk else section
            # 如果累积太大就发出去
            if len(current_chunk.encode("utf-8")) > 3000:
                all_ok &= _send_single(webhook_url, f"## {current_chunk}")
                current_chunk = ""

    if current_chunk:
        all_ok &= _send_single(webhook_url, f"## {current_chunk}")

    # 最后一条：要点总结 + 签名
    for section in sections[1:]:
        if "要点总结" in section or "总结" in section[:20]:
            all_ok &= _send_single(webhook_url, f"## {section}{signature}")
            break
    else:
        # 如果没有总结段落，签名加到最后一条
        pass

    if all_ok:
        logger.info(f"企业微信推送完成 (共 {len(sections)+1} 条)")
    return all_ok

